---- MODULE Broker ----
EXTENDS Integers, Sequences, FiniteSets, TLC
CONSTANTS SubscriberId, Topic, Topics

VARIABLES subscribers, messages, nextMsgId, subMsgs

(* --algorithm Broker --
  variables
    nextMsgId = 0

    loop

        var msg = messages[1];
        var topic = msg.topic;
        var msgId = msg.id;
        var payload = msg.payload;
        var subs = subscribers[topic];

          var sub = subs[1];
          var subId = sub.id;
          var subAddr = sub.addr;
          var subTopics = sub.topics;

            var subMsg = [id |-> msgId, topic |-> topic, payload |-> payload];
            var subMsgs = messages[subAddr];
            var subMsgs' = Append(subMsgs, subMsg);
            var messages' = [messages EXCEPT ![subAddr] = subMsgs'];
            var subscribers' = subscribers;
            var nextMsgId' = nextMsgId;

            var messages' = messages;
            var subscribers' = subscribers;
            var nextMsgId' = nextMsgId;

          var messages' = messages;
          var subscribers' = subscribers;
          var nextMsgId' = nextMsgId;

        var messages' = Tail(messages);

        var messages' = messages;
        var subscribers' = subscribers;
        var nextMsgId' = nextMsgId;

    end loop
  end
*)

